export function resolveJawcodeProvider(provider: string): string | undefined {
  return PROVIDER_ALIASES[provider];
}

export function getJawcodeModelMetadata(provider: string, modelId: string): JawcodeModelMetadata | undefined {
  const row = DATA[provider]?.find(r => r[0] === modelId);
  if (!row) return undefined;
  return rowToMetadata(provider, row);
}

export function getJawcodeModelMetadataCaseInsensitive(provider: string, modelId: string): JawcodeModelMetadata | undefined {
  const lower = modelId.toLowerCase();
  const row = DATA[provider]?.find(r => r[0].toLowerCase() === lower);
  if (!row) return undefined;
  return rowToMetadata(provider, row);
}

export function listJawcodeModelMetadata(provider: string): JawcodeModelMetadata[] {
  return (DATA[provider] ?? []).map(row => rowToMetadata(provider, row));
}

// Cross-provider model-level price fallback (260720 WP5): a model follows its
// official vendor price regardless of the serving provider. Exact modelId match in
// priority-ordered vendor bundles; first nonzero cost wins.
const COST_VENDOR_PRIORITY = ["anthropic","openai","google","moonshot","minimax","deepseek","xai","zai","mistral","cerebras","azure-openai","amazon-bedrock","xiaomi"];
export function findJawcodeCostByModelId(modelId: string): { provider: string; cost: { input: number; output: number; cacheRead: number; cacheWrite: number } } | undefined {
  for (const provider of COST_VENDOR_PRIORITY) {
    const row = DATA[provider]?.find(r => r[0] === modelId);
    if (!row) continue;
    const meta = rowToMetadata(provider, row);
    if (meta.cost && (meta.cost.input !== 0 || meta.cost.output !== 0 || meta.cost.cacheRead !== 0 || meta.cost.cacheWrite !== 0)) {
      return { provider, cost: meta.cost };
    }
  }
  return undefined;
}

function rowToMetadata(provider: string, row: Row): JawcodeModelMetadata {
  const [id, contextWindow, maxTokens, input, reasoning, wireModelId, costInput, costOutput, costCacheRead, costCacheWrite] = row;
  const hasCost = costInput != null && costOutput != null && costCacheRead != null && costCacheWrite != null;
  return {
    provider, id,
    ...(contextWindow != null ? { contextWindow } : {}),
    ...(maxTokens != null ? { maxTokens } : {}),
    ...(input ? { input: input.split(",") as ("text" | "image")[] } : {}),
    ...(reasoning != null ? { reasoning: reasoning === 1 } : {}),
    ...(wireModelId != null ? { wireModelId } : {}),
    ...(hasCost ? { cost: { input: costInput, output: costOutput, cacheRead: costCacheRead, cacheWrite: costCacheWrite } } : {}),
  };
}
